"""Embedded HTML for Vercel serverless."""
INDEX_HTML = '<!DOCTYPE html>\n<html lang="en" class="dark">\n<head>\n    <meta charset="UTF-8">\n    <meta name="viewport" content="width=device-width, initial-scale=1.0">\n    <title>Luhn Generator v3.4</title>\n    <script src="https://cdn.tailwindcss.com"></script>\n    <style>\n        * { box-sizing: border-box; }\n        body { background: #0a0a0f; color: #e2e8f0; font-family: \'Inter\', -apple-system, sans-serif; }\n        .bg-primary { background: #0a0a0f; }\n        .bg-secondary { background: #12121a; }\n        .bg-tertiary { background: #1a1a2e; }\n        .bg-card { background: #16162a; border: 1px solid #2a2a4a; }\n        .bg-card:hover { border-color: #6366f1; }\n        .accent { color: #818cf8; }\n        .accent-bg { background: #6366f1; }\n        .accent-bg:hover { background: #4f46e5; }\n        .glow { box-shadow: 0 0 20px rgba(99,102,241,0.15); }\n        textarea { background: #0f0f1a; border: 1px solid #2a2a4a; color: #e2e8f0; font-family: \'JetBrains Mono\', monospace; }\n        textarea:focus { outline: none; border-color: #6366f1; box-shadow: 0 0 0 2px rgba(99,102,241,0.2); }\n        select, input { background: #0f0f1a; border: 1px solid #2a2a4a; color: #e2e8f0; }\n        select:focus, input:focus { outline: none; border-color: #6366f1; }\n        .tab { padding: 8px 20px; cursor: pointer; border-bottom: 2px solid transparent; transition: all 0.2s; }\n        .tab:hover { color: #818cf8; }\n        .tab.active { color: #818cf8; border-bottom-color: #6366f1; }\n        .card-row { padding: 12px 16px; border-bottom: 1px solid #1a1a2e; transition: background 0.15s; }\n        .card-row:hover { background: #1a1a2e; }\n        .badge { padding: 2px 8px; border-radius: 9999px; font-size: 11px; font-weight: 600; }\n        .badge-live { background: #064e3b; color: #6ee7b7; }\n        .badge-die { background: #7f1d1d; color: #fca5a5; }\n        .badge-unknown { background: #78350f; color: #fcd34d; }\n        .copy-btn { cursor: pointer; padding: 4px 12px; border-radius: 6px; background: #1e1e3a; border: 1px solid #2a2a4a; color: #818cf8; font-size: 12px; transition: all 0.15s; }\n        .copy-btn:hover { background: #2a2a4a; }\n        .copy-btn.copied { background: #064e3b; color: #6ee7b7; border-color: #064e3b; }\n        @keyframes spin { to { transform: rotate(360deg); } }\n        .spinner { animation: spin 0.8s linear infinite; }\n        .grid-bg { background-image: linear-gradient(rgba(99,102,241,0.03) 1px, transparent 1px); background-size: 50px 50px; }\n    </style>\n</head>\n<body class="grid-bg min-h-screen">\n    <!-- Header -->\n    <header class="border-b border-gray-800 px-6 py-4">\n        <div class="max-w-6xl mx-auto flex items-center justify-between">\n            <div class="flex items-center gap-3">\n                <div class="w-8 h-8 rounded-lg accent-bg flex items-center justify-center text-white font-bold text-sm">L</div>\n                <h1 class="text-lg font-bold text-white">Luhn Generator <span class="accent text-sm">v3.4</span></h1>\n            </div>\n            <div class="flex items-center gap-4 text-sm text-gray-400">\n                <span id="stats-display">—</span>\n            </div>\n        </div>\n    </header>\n\n    <!-- Main -->\n    <main class="max-w-6xl mx-auto px-6 py-8">\n        <!-- Tabs -->\n        <div class="flex gap-1 mb-6 border-b border-gray-800">\n            <div class="tab active" data-tab="genlive" onclick="switchTab(\'genlive\')">⚡ Generate + Live</div>\n            <div class="tab" data-tab="generate" onclick="switchTab(\'generate\')">🔧 Generate Only</div>\n            <div class="tab" data-tab="enrich" onclick="switchTab(\'enrich\')">🔄 Enrich</div>\n            <div class="tab" data-tab="lookup" onclick="switchTab(\'lookup\')">🔍 BIN Lookup</div>\n            <div class="tab" data-tab="format" onclick="switchTab(\'format\')">🏪 Format</div>\n            <div class="tab" data-tab="tracker" onclick="switchTab(\'tracker\')">📊 Tracker</div>\n        </div>\n\n        <!-- Generate + Live Tab -->\n        <div id="tab-genlive" class="tab-content">\n            <div class="grid grid-cols-1 lg:grid-cols-3 gap-6">\n                <!-- Controls -->\n                <div class="bg-card rounded-xl p-6">\n                    <h2 class="text-white font-semibold mb-4">⚡ Generate + Auto-Check</h2>\n                    <p class="text-xs text-gray-400 mb-4">Generate cards → auto-check on chkr.cc → show only Live cards</p>\n                    <div class="space-y-4">\n                        <div>\n                            <label class="text-sm text-gray-400 mb-1 block">How many cards to check</label>\n                            <input id="gl-count" type="number" value="50" min="1" max="500" class="w-full rounded-lg px-3 py-2 text-sm">\n                        </div>\n                        <div>\n                            <label class="text-sm text-gray-400 mb-1 block">Custom BINs (comma-separated)</label>\n                            <input id="gl-bins" type="text" value="400344, 515000, 525000, 401288, 402400, 406032, 520000, 530000, 535000, 540000, 545000, 550000, 6233586370" class="w-full rounded-lg px-3 py-2 text-sm">\n                            <div class="mt-2 space-y-1">\n                                <div class="text-xs text-gray-500 font-semibold mb-1">🎯 Best BINs by Live Rate:</div>\n                                <button onclick="setBins(\'400344, 515000, 525000\')" class="text-xs text-indigo-400 hover:text-indigo-300 block">⭐ Top 3 (8-12% rate)</button>\n                                <button onclick="setBins(\'400344, 401288, 402400, 406032, 400000, 400001, 400002, 400003, 400004, 400005, 400006, 400007\')" class="text-xs text-gray-400 hover:text-indigo-300 block">🇺🇸 All US Visa</button>\n                                <button onclick="setBins(\'515000, 525000, 520000, 530000, 535000, 540000, 545000, 550000, 510000, 510001, 510002, 510003, 510004, 510005\')" class="text-xs text-gray-400 hover:text-indigo-300 block">🇺🇸 All US Mastercard</button>\n                                <button onclick="setBins(\'450060, 450088, 450120, 450157, 450200, 451500, 552000, 553000, 554000, 555000, 556000, 557000, 558000, 559000\')" class="text-xs text-gray-400 hover:text-indigo-300 block">🇮🇩 All Indonesia</button>\n                                <button onclick="setBins(\'6233586370, 622000, 623000, 624000, 625000\')" class="text-xs text-gray-400 hover:text-indigo-300 block">🇨🇳 All UnionPay</button>\n                                <button onclick="setBins(\'446200, 453200, 455600, 530000, 535000, 540000, 545000, 550000\')" class="text-xs text-gray-400 hover:text-indigo-300 block">🇬🇧 All UK</button>\n                                <button onclick="setBins(\'352800, 352900, 353000, 354000, 355000, 356000, 357000, 358000, 359000\')" class="text-xs text-gray-400 hover:text-indigo-300 block">🇯🇵 All JCB</button>\n                                <button onclick="setBins(\'400344, 515000, 525000, 401288, 402400, 406032, 520000, 530000, 535000, 540000, 545000, 550000, 6233586370, 450060, 450088, 450120, 450157, 450200, 451500, 552000, 553000, 554000, 555000, 556000, 557000, 558000, 559000, 446200, 453200, 455600, 352800, 352900, 353000, 354000, 355000, 356000, 357000, 358000, 359000, 375000, 376000, 377000, 378000\')" class="text-xs text-green-400 hover:text-green-300 block font-bold">🔥 ALL BEST BINs (max chance)</button>\n                            </div>\n                        </div>\n                        <div>\n                            <label class="text-sm text-gray-400 mb-1 block">Card Types</label>\n                            <select id="gl-types" multiple class="w-full rounded-lg px-3 py-2 text-sm h-20">\n                                <option value="visa" selected>Visa</option>\n                                <option value="mastercard" selected>Mastercard</option>\n                                <option value="amex">Amex</option>\n                                <option value="jcb">JCB</option>\n                                <option value="unionpay">UnionPay</option>\n                            </select>\n                        </div>\n                        <button id="gl-btn" onclick="generateAndCheck()" class="w-full accent-bg text-white rounded-lg py-2.5 font-medium text-sm hover:opacity-90 transition">\n                            ⚡ Generate + Check Live\n                        </button>\n                    </div>\n                </div>\n\n                <!-- Results -->\n                <div class="lg:col-span-2 bg-card rounded-xl p-6">\n                    <div class="flex items-center justify-between mb-4">\n                        <div>\n                            <h2 class="text-white font-semibold">Live Cards</h2>\n                            <div id="gl-progress" class="text-xs text-gray-500 mt-1"></div>\n                        </div>\n                        <div class="flex gap-2">\n                            <button onclick="copyLivePipe()" class="copy-btn" id="gl-copy-btn">📋 Copy Live Cards</button>\n                        </div>\n                    </div>\n                    <!-- Progress bar -->\n                    <div id="gl-progress-bar-wrap" class="hidden mb-4">\n                        <div class="w-full bg-gray-800 rounded-full h-2">\n                            <div id="gl-progress-bar" class="accent-bg h-2 rounded-full transition-all duration-300" style="width: 0%"></div>\n                        </div>\n                    </div>\n                    <div id="gl-results" class="text-sm text-gray-300">\n                        <div class="text-center text-gray-500 py-12">Set BIN and count, then click Generate + Check</div>\n                    </div>\n                </div>\n            </div>\n        </div>\n\n        <!-- Generate Only Tab -->\n        <div id="tab-generate" class="tab-content">\n            <div class="grid grid-cols-1 lg:grid-cols-3 gap-6">\n                <!-- Controls -->\n                <div class="bg-card rounded-xl p-6">\n                    <h2 class="text-white font-semibold mb-4">Generate Cards</h2>\n                    <div class="space-y-4">\n                        <div>\n                            <label class="text-sm text-gray-400 mb-1 block">Count</label>\n                            <input id="gen-count" type="number" value="10" min="1" max="500" class="w-full rounded-lg px-3 py-2 text-sm">\n                        </div>\n                        <div>\n                            <label class="text-sm text-gray-400 mb-1 block">Custom BINs (comma-separated)</label>\n                            <input id="gen-bins" type="text" placeholder="515000, 525000, 400344" class="w-full rounded-lg px-3 py-2 text-sm">\n                        </div>\n                        <div>\n                            <label class="text-sm text-gray-400 mb-1 block">Card Types</label>\n                            <select id="gen-types" multiple class="w-full rounded-lg px-3 py-2 text-sm h-28">\n                                <option value="visa" selected>Visa</option>\n                                <option value="mastercard" selected>Mastercard</option>\n                                <option value="amex">Amex</option>\n                                <option value="discover">Discover</option>\n                                <option value="jcb">JCB</option>\n                                <option value="unionpay">UnionPay</option>\n                            </select>\n                        </div>\n                        <button onclick="generateCards()" class="w-full accent-bg text-white rounded-lg py-2.5 font-medium text-sm hover:opacity-90 transition">\n                            ⚡ Generate\n                        </button>\n                    </div>\n                </div>\n\n                <!-- Results -->\n                <div class="lg:col-span-2 bg-card rounded-xl p-6">\n                    <div class="flex items-center justify-between mb-4">\n                        <h2 class="text-white font-semibold">Results</h2>\n                        <div class="flex gap-2">\n                            <button onclick="copyPipe()" class="copy-btn" id="copy-pipe-btn">📋 Copy Pipe</button>\n                            <button onclick="copyJSON()" class="copy-btn" id="copy-json-btn">{ } Copy JSON</button>\n                        </div>\n                    </div>\n                    <div id="gen-results" class="text-sm text-gray-300">\n                        <div class="text-center text-gray-500 py-12">Click Generate to create cards</div>\n                    </div>\n                </div>\n            </div>\n        </div>\n\n        <!-- Enrich Tab -->\n        <div id="tab-enrich" class="tab-content hidden">\n            <div class="grid grid-cols-1 lg:grid-cols-2 gap-6">\n                <div class="bg-card rounded-xl p-6">\n                    <h2 class="text-white font-semibold mb-4">Enrich Cards</h2>\n                    <div class="space-y-4">\n                        <div>\n                            <label class="text-sm text-gray-400 mb-1 block">Cards (pipe-delimited, one per line)</label>\n                            <textarea id="enrich-input" rows="10" class="w-full rounded-lg px-3 py-2 text-sm font-mono" placeholder="5150002791221529|01|2029|215&#10;5250003014805063|10|2028|238"></textarea>\n                        </div>\n                        <button onclick="enrichCards()" class="w-full accent-bg text-white rounded-lg py-2.5 font-medium text-sm">\n                            🔄 Enrich\n                        </button>\n                    </div>\n                </div>\n                <div class="bg-card rounded-xl p-6">\n                    <div class="flex items-center justify-between mb-4">\n                        <h2 class="text-white font-semibold">Enriched Results</h2>\n                        <button onclick="copyEnriched()" class="copy-btn" id="copy-enrich-btn">📋 Copy</button>\n                    </div>\n                    <div id="enrich-results" class="text-sm text-gray-300">\n                        <div class="text-center text-gray-500 py-12">Paste cards and click Enrich</div>\n                    </div>\n                </div>\n            </div>\n        </div>\n\n        <!-- Lookup Tab -->\n        <div id="tab-lookup" class="tab-content hidden">\n            <div class="grid grid-cols-1 lg:grid-cols-2 gap-6">\n                <div class="bg-card rounded-xl p-6">\n                    <h2 class="text-white font-semibold mb-4">BIN Lookup</h2>\n                    <div class="space-y-4">\n                        <div>\n                            <label class="text-sm text-gray-400 mb-1 block">BIN Numbers (comma-separated)</label>\n                            <input id="lookup-bins" type="text" placeholder="400344, 515000, 6233586370" class="w-full rounded-lg px-3 py-2 text-sm">\n                        </div>\n                        <button onclick="lookupBins()" class="w-full accent-bg text-white rounded-lg py-2.5 font-medium text-sm">\n                            🔍 Lookup\n                        </button>\n                    </div>\n                </div>\n                <div class="bg-card rounded-xl p-6">\n                    <h2 class="text-white font-semibold mb-4">BIN Info</h2>\n                    <div id="lookup-results" class="text-sm text-gray-300">\n                        <div class="text-center text-gray-500 py-12">Enter BIN numbers and click Lookup</div>\n                    </div>\n                </div>\n            </div>\n        </div>\n\n        <!-- Format Tab -->\n        <div id="tab-format" class="tab-content hidden">\n            <div class="grid grid-cols-1 lg:grid-cols-2 gap-6">\n                <div class="bg-card rounded-xl p-6">\n                    <h2 class="text-white font-semibold mb-4">Site-Specific Format</h2>\n                    <div class="space-y-4">\n                        <div>\n                            <label class="text-sm text-gray-400 mb-1 block">Cards (pipe-delimited, one per line)</label>\n                            <textarea id="format-input" rows="6" class="w-full rounded-lg px-3 py-2 text-sm font-mono" placeholder="5150002791221529|01|2029|215"></textarea>\n                        </div>\n                        <div>\n                            <label class="text-sm text-gray-400 mb-1 block">Target Site</label>\n                            <select id="format-site" class="w-full rounded-lg px-3 py-2 text-sm">\n                                <option value="stripe">Stripe</option>\n                                <option value="shopify">Shopify</option>\n                                <option value="paypal">PayPal</option>\n                                <option value="generic">Generic</option>\n                            </select>\n                        </div>\n                        <button onclick="formatCards()" class="w-full accent-bg text-white rounded-lg py-2.5 font-medium text-sm">\n                            🏪 Format\n                        </button>\n                    </div>\n                </div>\n                <div class="bg-card rounded-xl p-6">\n                    <div class="flex items-center justify-between mb-4">\n                        <h2 class="text-white font-semibold">Formatted Output</h2>\n                        <button onclick="copyFormatted()" class="copy-btn" id="copy-format-btn">📋 Copy</button>\n                    </div>\n                    <div id="format-results" class="text-sm text-gray-300">\n                        <div class="text-center text-gray-500 py-12">Paste cards and select a site</div>\n                    </div>\n                </div>\n            </div>\n        </div>\n\n        <!-- Tracker Tab -->\n        <div id="tab-tracker" class="tab-content hidden">\n            <div class="grid grid-cols-1 lg:grid-cols-2 gap-6">\n                <div class="bg-card rounded-xl p-6">\n                    <h2 class="text-white font-semibold mb-4">📊 Live Card Tracker</h2>\n                    <div id="tracker-stats" class="text-sm text-gray-300">\n                        <div class="text-center text-gray-500 py-12">Loading...</div>\n                    </div>\n                </div>\n                <div class="bg-card rounded-xl p-6">\n                    <h2 class="text-white font-semibold mb-4">🎯 BIN Recommendations</h2>\n                    <div id="tracker-recs" class="text-sm text-gray-300">\n                        <div class="text-center text-gray-500 py-12">No data yet</div>\n                    </div>\n                </div>\n            </div>\n        </div>\n    </main>\n\n    <script>\n    // State\n    let lastGenCards = [];\n    let lastEnrichCards = [];\n    let lastFormatCards = [];\n\n    // Tab switching\n    function switchTab(tab) {\n        document.querySelectorAll(\'.tab\').forEach(t => t.classList.remove(\'active\'));\n        document.querySelector(`[data-tab="${tab}"]`).classList.add(\'active\');\n        document.querySelectorAll(\'.tab-content\').forEach(c => c.classList.add(\'hidden\'));\n        document.getElementById(`tab-${tab}`).classList.remove(\'hidden\');\n        if (tab === \'tracker\') loadTracker();\n    }\n    // Show genlive tab by default\n    document.getElementById(\'tab-generate\').classList.add(\'hidden\');\n\n    // API calls\n    async function api(url, body = null) {\n        const opts = body ? { method: \'POST\', headers: { \'Content-Type\': \'application/json\' }, body: JSON.stringify(body) } : {};\n        const res = await fetch(url, opts);\n        return res.json();\n    }\n\n    // Generate\n    async function generateCards() {\n        const count = parseInt(document.getElementById(\'gen-count\').value) || 10;\n        const binsStr = document.getElementById(\'gen-bins\').value.trim();\n        const bins = binsStr ? binsStr.split(\',\').map(b => b.trim()).filter(Boolean) : null;\n        const typesSelect = document.getElementById(\'gen-types\');\n        const types = Array.from(typesSelect.selectedOptions).map(o => o.value);\n\n        document.getElementById(\'gen-results\').innerHTML = \'<div class="text-center py-12"><svg class="spinner inline w-6 h-6 accent" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10" stroke="currentColor" stroke-width="3" fill="none" stroke-dasharray="60" stroke-dashoffset="20"/></svg></div>\';\n\n        const data = await api(\'/api/generate\', { count, bins, types: types.length ? types : null });\n        lastGenCards = data.cards;\n\n        let html = `<div class="mb-3 text-xs text-gray-500">${data.count} cards generated</div>`;\n        html += \'<div class="space-y-1 max-h-[500px] overflow-y-auto">\';\n        \n        data.cards.forEach((c, i) => {\n            const addr = c.billing_address || {};\n            const flag = getFlag(addr.country || \'US\');\n            html += `\n            <div class="card-row rounded-lg">\n                <div class="flex items-center justify-between">\n                    <code class="text-indigo-300 font-mono text-xs">${c.raw_number}|${c.expiry.split(\'/\')[0]}|${c.expiry.split(\'/\')[1]}|${c.cvv}</code>\n                    <span class="text-xs text-gray-500">${c.type}</span>\n                </div>\n                <div class="mt-1 text-xs text-gray-400">\n                    ${flag} <span class="text-gray-300">${c.name}</span> · ${c.phone || \'—\'} · ${addr.street || \'\'}, ${addr.city || \'\'} ${addr.state || \'\'} ${addr.zip || \'\'}\n                </div>\n                <div class="mt-0.5 text-xs text-gray-500">\n                    BIN: ${c.bin} · ${c.type} · ${addr.country || \'—\'}\n                </div>\n            </div>`;\n        });\n        html += \'</div>\';\n        document.getElementById(\'gen-results\').innerHTML = html;\n    }\n\n    // Enrich\n    async function enrichCards() {\n        const input = document.getElementById(\'enrich-input\').value.trim();\n        if (!input) return;\n        const cards = input.split(\'\\n\').map(l => l.trim()).filter(Boolean);\n\n        document.getElementById(\'enrich-results\').innerHTML = \'<div class="text-center py-12"><svg class="spinner inline w-6 h-6 accent" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10" stroke="currentColor" stroke-width="3" fill="none" stroke-dasharray="60" stroke-dashoffset="20"/></svg></div>\';\n\n        const data = await api(\'/api/enrich\', { cards });\n        lastEnrichCards = data.cards;\n\n        let html = `<div class="mb-3 text-xs text-gray-500">${data.count} cards enriched</div>`;\n        html += \'<div class="space-y-1 max-h-[500px] overflow-y-auto">\';\n        \n        data.cards.forEach((c, i) => {\n            if (c.error) {\n                html += `<div class="card-row rounded-lg text-red-400">Error: ${c.error}</div>`;\n                return;\n            }\n            const addr = c.billing_address || {};\n            const flag = getFlag(c.country_code || addr.country || \'US\');\n            html += `\n            <div class="card-row rounded-lg">\n                <div class="flex items-center justify-between">\n                    <code class="text-indigo-300 font-mono text-xs">${c.raw_number}|${(c.expiry||\'12/2028\').split(\'/\')[0]}|${(c.expiry||\'12/2028\').split(\'/\')[1]}|${c.cvv||\'000\'}</code>\n                </div>\n                <div class="mt-1 text-xs text-gray-400">\n                    ${flag} <span class="text-gray-300">${c.name}</span> · ${c.phone || \'—\'} · ${addr.street || \'\'}, ${addr.city || \'\'} ${addr.state || \'\'} ${addr.zip || \'\'}\n                </div>\n                <div class="mt-0.5 text-xs text-gray-500">\n                    BIN: ${c.bin} · ${c.bank} · ${c.country || \'—\'} (${c.country_code || \'—\'})\n                </div>\n            </div>`;\n        });\n        html += \'</div>\';\n        document.getElementById(\'enrich-results\').innerHTML = html;\n    }\n\n    // Lookup\n    async function lookupBins() {\n        const binsStr = document.getElementById(\'lookup-bins\').value.trim();\n        if (!binsStr) return;\n        const bins = binsStr.split(\',\').map(b => b.trim()).filter(Boolean);\n\n        document.getElementById(\'lookup-results\').innerHTML = \'<div class="text-center py-12"><svg class="spinner inline w-6 h-6 accent" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10" stroke="currentColor" stroke-width="3" fill="none" stroke-dasharray="60" stroke-dashoffset="20"/></svg></div>\';\n\n        const data = await api(\'/api/lookup\', { bins });\n\n        let html = \'<div class="space-y-3">\';\n        data.results.forEach(r => {\n            const flag = getFlag(r.country_code || \'??\');\n            html += `\n            <div class="bg-tertiary rounded-lg p-4">\n                <div class="flex items-center justify-between mb-2">\n                    <span class="text-white font-mono font-bold">${r.bin}</span>\n                    <span class="badge badge-live">${r.scheme || r.type || \'—\'}</span>\n                </div>\n                <div class="text-sm space-y-1">\n                    <div>🏦 ${r.bank || \'Unknown\'}</div>\n                    <div>${flag} ${r.country || \'Unknown\'} (${r.country_code || \'??\'})</div>\n                    <div>💳 ${r.brand || r.type || \'Unknown\'} · ${r.type || \'—\'}</div>\n                    ${r.bank_city ? `<div>📍 ${r.bank_city}</div>` : \'\'}\n                    ${r.bank_url ? `<div>🔗 ${r.bank_url}</div>` : \'\'}\n                </div>\n            </div>`;\n        });\n        html += \'</div>\';\n        document.getElementById(\'lookup-results\').innerHTML = html;\n    }\n\n    // Format\n    async function formatCards() {\n        const input = document.getElementById(\'format-input\').value.trim();\n        if (!input) return;\n        const cards = input.split(\'\\n\').map(l => l.trim()).filter(Boolean);\n        const site = document.getElementById(\'format-site\').value;\n\n        document.getElementById(\'format-results\').innerHTML = \'<div class="text-center py-12"><svg class="spinner inline w-6 h-6 accent" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10" stroke="currentColor" stroke-width="3" fill="none" stroke-dasharray="60" stroke-dashoffset="20"/></svg></div>\';\n\n        const data = await api(\'/api/format\', { cards, site });\n        lastFormatCards = data.formatted;\n\n        let html = `<div class="mb-3 text-xs text-gray-500">${data.count} cards formatted for ${site}</div>`;\n        html += \'<div class="space-y-3 max-h-[500px] overflow-y-auto">\';\n        \n        data.formatted.forEach((f, i) => {\n            html += `<div class="bg-tertiary rounded-lg p-3"><pre class="text-xs text-gray-300 overflow-x-auto">${JSON.stringify(f, null, 2)}</pre></div>`;\n        });\n        html += \'</div>\';\n        document.getElementById(\'format-results\').innerHTML = html;\n    }\n\n    // Tracker\n    async function loadTracker() {\n        try {\n            const [stats, recs] = await Promise.all([api(\'/api/stats\'), api(\'/api/recommend\')]);\n            \n            let statsHtml = \'<div class="grid grid-cols-2 gap-3">\';\n            statsHtml += `<div class="bg-tertiary rounded-lg p-3 text-center"><div class="text-2xl font-bold text-white">${stats.total_checked}</div><div class="text-xs text-gray-400">Total Checked</div></div>`;\n            statsHtml += `<div class="bg-tertiary rounded-lg p-3 text-center"><div class="text-2xl font-bold text-green-400">${stats.live}</div><div class="text-xs text-gray-400">Live</div></div>`;\n            statsHtml += `<div class="bg-tertiary rounded-lg p-3 text-center"><div class="text-2xl font-bold text-red-400">${stats.die}</div><div class="text-xs text-gray-400">Die</div></div>`;\n            statsHtml += `<div class="bg-tertiary rounded-lg p-3 text-center"><div class="text-2xl font-bold text-yellow-400">${stats.overall_live_rate}</div><div class="text-xs text-gray-400">Live Rate</div></div>`;\n            statsHtml += \'</div>\';\n            document.getElementById(\'tracker-stats\').innerHTML = statsHtml;\n\n            if (recs.recommendations && recs.recommendations.length) {\n                let recHtml = \'<div class="space-y-2">\';\n                recs.recommendations.forEach(r => {\n                    recHtml += `<div class="bg-tertiary rounded-lg p-3">\n                        <div class="flex justify-between"><span class="text-white font-mono">${r.bin}</span><span class="text-green-400 font-bold">${r.live_rate}</span></div>\n                        <div class="text-xs text-gray-400 mt-1">${r.bank} · ${r.country} · ${r.total_checked} checked</div>\n                    </div>`;\n                });\n                recHtml += \'</div>\';\n                document.getElementById(\'tracker-recs\').innerHTML = recHtml;\n            }\n        } catch(e) {\n            document.getElementById(\'tracker-stats\').innerHTML = \'<div class="text-red-400">Error loading stats</div>\';\n        }\n    }\n\n    // Copy helpers\n    function copyPipe() {\n        if (!lastGenCards.length) return;\n        const text = lastGenCards.map(c => {\n            const [m, y] = c.expiry.split(\'/\');\n            return `${c.raw_number}|${m}|${y}|${c.cvv}`;\n        }).join(\'\\n\');\n        copyToClipboard(text, \'copy-pipe-btn\');\n    }\n\n    function copyJSON() {\n        if (!lastGenCards.length) return;\n        copyToClipboard(JSON.stringify(lastGenCards, null, 2), \'copy-json-btn\');\n    }\n\n    function copyEnriched() {\n        if (!lastEnrichCards.length) return;\n        const text = lastEnrichCards.map(c => {\n            if (c.error) return \'\';\n            const exp = c.expiry || \'12/2028\';\n            const [m, y] = exp.split(\'/\');\n            return `${c.raw_number}|${m}|${y}|${c.cvv || \'000\'}`;\n        }).filter(Boolean).join(\'\\n\');\n        copyToClipboard(text, \'copy-enrich-btn\');\n    }\n\n    function copyFormatted() {\n        if (!lastFormatCards.length) return;\n        copyToClipboard(JSON.stringify(lastFormatCards, null, 2), \'copy-format-btn\');\n    }\n\n    function copyToClipboard(text, btnId) {\n        navigator.clipboard.writeText(text).then(() => {\n            const btn = document.getElementById(btnId);\n            btn.textContent = \'✅ Copied!\';\n            btn.classList.add(\'copied\');\n            setTimeout(() => {\n                btn.textContent = btn.getAttribute(\'data-original\') || \'📋 Copy\';\n                btn.classList.remove(\'copied\');\n            }, 2000);\n        });\n    }\n\n    // Flag helper\n    function getFlag(cc) {\n        const flags = {\'US\':\'🇺🇸\',\'UK\':\'🇬🇧\',\'GB\':\'🇬🇧\',\'ID\':\'🇮🇩\',\'JP\':\'🇯🇵\',\'KR\':\'🇰🇷\',\'DE\':\'🇩🇪\',\'FR\':\'🇫🇷\',\'AU\':\'🇦🇺\',\'CN\':\'🇨🇳\',\'BR\':\'🇧🇷\',\'IN\':\'🇮🇳\',\'ES\':\'🇪🇸\',\'IT\':\'🇮🇹\',\'NL\':\'🇳🇱\',\'CA\':\'🇨🇦\',\'SG\':\'🇸🇬\',\'MY\':\'🇲🇾\',\'TH\':\'🇹🇭\'};\n        return flags[cc?.toUpperCase()] || \'🏳️\';\n    }\n\n    // Init\n    document.querySelectorAll(\'.copy-btn\').forEach(btn => btn.setAttribute(\'data-original\', btn.textContent));\n\n    // BIN preset helper\n    function setBins(bins) {\n        document.getElementById(\'gl-bins\').value = bins;\n    }\n\n    // ═══ Generate + Live Check ═══\n\n    let liveCards = []; // Store live cards for copy\n\n    async function generateAndCheck() {\n        const count = parseInt(document.getElementById(\'gl-count\').value) || 25;\n        const binsStr = document.getElementById(\'gl-bins\').value.trim();\n        const bins = binsStr ? binsStr.split(\',\').map(b => b.trim()).filter(Boolean) : null;\n        const typesSelect = document.getElementById(\'gl-types\');\n        const types = Array.from(typesSelect.selectedOptions).map(o => o.value);\n        \n        const btn = document.getElementById(\'gl-btn\');\n        btn.disabled = true;\n        btn.innerHTML = \'<svg class="spinner inline w-4 h-4 mr-2" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10" stroke="currentColor" stroke-width="3" fill="none" stroke-dasharray="60" stroke-dashoffset="20"/></svg> Generating...\';\n        \n        // Step 1: Generate cards via API\n        const genData = await api(\'/api/generate\', { count, bins, types: types.length ? types : null });\n        const allCards = genData.cards;\n        \n        document.getElementById(\'gl-results\').innerHTML = \'<div class="text-center py-8"><div class="text-gray-400 mb-2">Checking \' + allCards.length + \' cards on chkr.cc...</div><div class="text-xs text-gray-500">This may take ~\' + Math.ceil(allCards.length * 1.5) + \' seconds</div></div>\';\n        document.getElementById(\'gl-progress-bar-wrap\').classList.remove(\'hidden\');\n        \n        // Step 2: Check each card via chkr.cc API (from browser = no rate limit)\n        liveCards = [];\n        let dieCount = 0;\n        let unknownCount = 0;\n        let checkedCount = 0;\n        \n        for (let i = 0; i < allCards.length; i++) {\n            const c = allCards[i];\n            const pipeStr = `${c.raw_number}|${c.expiry.split(\'/\')[0]}|${c.expiry.split(\'/\')[1]}|${c.cvv}`;\n            \n            try {\n                const res = await fetch(\'https://api.chkr.cc/\', {\n                    method: \'POST\',\n                    headers: { \'Content-Type\': \'application/json\' },\n                    body: JSON.stringify({ data: pipeStr })\n                });\n                const j = await res.json();\n                checkedCount++;\n                \n                if (j.code === 1) {\n                    // LIVE!\n                    liveCards.push({ ...c, pipe: pipeStr, gate: j.message || \'OK\' });\n                } else if (j.code === 0) {\n                    dieCount++;\n                } else {\n                    unknownCount++;\n                }\n            } catch(e) {\n                checkedCount++;\n                unknownCount++;\n            }\n            \n            // Update progress\n            const pct = Math.round((checkedCount / allCards.length) * 100);\n            document.getElementById(\'gl-progress-bar\').style.width = pct + \'%\';\n            document.getElementById(\'gl-progress\').innerHTML = \n                `Checked: ${checkedCount}/${allCards.length} | ` +\n                `<span class="text-green-400">Live: ${liveCards.length}</span> | ` +\n                `<span class="text-red-400">Die: ${dieCount}</span> | ` +\n                `<span class="text-yellow-400">Unknown: ${unknownCount}</span>`;\n            \n            // Update live cards display in real-time\n            if (liveCards.length > 0) {\n                renderLiveCards();\n            }\n            \n            // Small delay to avoid overwhelming\n            await new Promise(r => setTimeout(r, 1200));\n        }\n        \n        // Done!\n        btn.disabled = false;\n        btn.innerHTML = \'⚡ Generate + Check Live\';\n        document.getElementById(\'gl-progress-bar-wrap\').classList.add(\'hidden\');\n        \n        if (liveCards.length === 0) {\n            document.getElementById(\'gl-results\').innerHTML = \n                \'<div class="text-center py-12">\' +\n                \'<div class="text-gray-400 mb-2">No Live cards found in this batch</div>\' +\n                \'<div class="text-xs text-gray-500">Try different BINs or increase count</div></div>\';\n        } else {\n            document.getElementById(\'gl-progress\').innerHTML += \' | ✅ Done!\';\n            renderLiveCards();\n        }\n    }\n\n    function renderLiveCards() {\n        let html = \'<div class="space-y-1 max-h-[500px] overflow-y-auto">\';\n        liveCards.forEach((c, i) => {\n            const addr = c.billing_address || {};\n            const flag = getFlag(addr.country || \'US\');\n            html += `\n            <div class="card-row rounded-lg border-l-2 border-green-500">\n                <div class="flex items-center justify-between">\n                    <code class="text-green-300 font-mono text-xs font-bold">${c.pipe}</code>\n                    <span class="badge badge-live">LIVE ✅</span>\n                </div>\n                <div class="mt-1 text-xs text-gray-400">\n                    ${flag} <span class="text-gray-300">${c.name}</span> · ${c.phone || \'—\'}\n                </div>\n                <div class="mt-0.5 text-xs text-gray-400">\n                    📍 ${addr.street || \'\'}, ${addr.city || \'\'} ${addr.state || \'\'} ${addr.zip || \'\'}\n                </div>\n                <div class="mt-0.5 text-xs text-gray-500">\n                    BIN: ${c.bin} · ${c.type} · ${addr.country || \'—\'} · Gate: ${c.gate || \'—\'}\n                </div>\n            </div>`;\n        });\n        html += \'</div>\';\n        document.getElementById(\'gl-results\').innerHTML = html;\n    }\n\n    function copyLivePipe() {\n        if (!liveCards.length) return;\n        const text = liveCards.map(c => c.pipe).join(\'\\n\');\n        copyToClipboard(text, \'gl-copy-btn\');\n    }\n    </script>\n</body>\n</html>\n'
